import{_ as o,o as r,c as t,a2 as e}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F07: 存貨週轉效率同業對比","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F07_存貨週轉效率同業對比_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F07_存貨週轉效率同業對比_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/財務組/F07_存貨週轉效率同業對比_投資研究員.md"};function s(l,n,a,g,c,d){return r(),t("div",null,[...n[0]||(n[0]=[e('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f07-存貨週轉效率同業對比" tabindex="-1">F07: 存貨週轉效率同業對比 <a class="header-anchor" href="#f07-存貨週轉效率同業對比" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F07</li><li><strong>題目：</strong> 存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「產業週轉效能」與「供應鏈競爭力對位」。能透過橫向對比識別企業管理水平的「階位差距」，是判定公司營運效能是否具備「產業領先地位」的權威專家。</li><li><strong>意圖：</strong> 執行「供應鏈效率與營運週期審計」。透過對比同業存貨週轉天數，判定公司是否具備更強的「去化能力」與「市場議價權」。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockFinancialStatements</code> 獲取營業成本，結合資產負債表提取存貨餘額，測算「存貨週轉天數 (Inventory Turnover Days)」。</li><li><strong>【競爭力對位：Web Search】</strong>：搜尋同業競爭對手之存貨週轉率，或使用 <strong>優分析/各大財經平台</strong>、<strong>優分析</strong> 之同業比較功能。</li><li><strong>【穿透校準：產業研報】</strong>：獲取該產業目前之「庫存水位正常值 (Standard Inventory Level)」。</li></ol></li><li><strong>邏輯：</strong> 執行「週轉階差算則」——分析存貨天數對比產業平均之偏差值；執行「營運週期壓力測試」——計算「DIO + DSO」之總天數變動趨勢。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py inventory_check [股號]</code> → 取得 DIO、DSO、現金循環</li><li><strong>同業對比</strong>：用 <code>web_search</code> 搜尋同業存貨週轉率（如 <code>[股號] 同業 存貨週轉率 比較</code>）</li><li><strong>判讀</strong>：對比同業中位值，若 DIO 高於同業 25% 以上標註為供應鏈弱勢</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具從年報提取「存貨明細」</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①答詢詳解 ≥200 字、專家評析 ≥200 字；②空頭視角 ≥2 個關鍵字（風險、利空、壓力等）；③診斷評級需有具體數據佐證</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【週轉事實優先】</strong>：智慧體<strong>必須</strong>計算出具體的「存貨週轉天數 (DIO)」。嚴禁在未量化天數前得出效率優劣結論。</li><li><strong>【同業階差審核】</strong>：智慧體必須抓取至少 1 家同類型競業之週轉率數據進行橫向對比。若本企週轉率低於同業平均 25% 以上，必須標註為「供應鏈管理弱勢」。</li><li><strong>【營運週期透視】</strong>：計算「應收天數 (DSO) + 存貨天數 (DIO)」。若整體週期拉長超過 15 天且無合理擴產理由，智慧體必須判定為「資產效率失速」。</li><li><strong>【通路博弈分析】</strong>：判定週轉率背後的意義——是來自「供不應求」的領先優勢，還是「通路管理能力」的溢價。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：絕對禁用「管理卓越」、「表現平平」。必須量化為具體的「Inventory Days」與「營運週期變動量 (Days Change)」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f07-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F07 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f07-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F07 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「週轉階差+營運流速」結構（例：DIO 為 X 天，優於同業中位值 Y %，整體營運週期 [擴張/收縮]，產品去化動能 [強勁/停滯]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：週轉效率顯著優於產業均值（領先 20% 以上），具備極致的供應鏈掌控力，資金回籠速度極快，展現出強大的市場主導權。</li><li><strong>A (良)</strong>：週轉效率穩定且位居同業中段以上，資產變現路徑通暢，與公司營收成長步調高度一致。</li><li><strong>B (持平)</strong>：週轉率連續三季下滑且遠低於同業平均，顯示產品競爭力衰退、管理失靈或正陷入嚴重的通路庫存塞車危機。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>analysis</code> 財務指標與同業對位數據來源。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注「長短料」或「供應鏈斷裂」之歷史背景。若週轉率下降是為了建立「安全庫存」以因應大幅成長的合約負債，專家應在此處進行「策略性備貨」之正面背書，否則應診斷為「生產過剩」。判定這是「效率王者 (Efficiency Leader)」還是「呆滯倉庫 (Sluggish Inventory)」。</li></ul>',12)])])}const f=o(i,[["render",s]]);export{h as __pageData,f as default};
